/**
 * Brand icons for Atlas apps. Each icon is a hand-tuned multicolor SVG
 * supplied by design — used in the dockbar (left global sidebar) where the
 * app's brand mark belongs, instead of the generic lucide-react placeholder.
 *
 * Each component takes a `size` prop (default 24, dockbar renders at 16).
 * All internal SVG IDs (gradients, masks, filters) are namespaced per icon
 * so multiple icons can render on the same page without ID collisions.
 */

interface IconProps {
  size?: number;
  className?: string;
  style?: React.CSSProperties;
}

/** Set of brand-icon app ids whose SVG should fill the dock card edge-to-edge
 * (no separate background card). Used by apps whose artwork is itself a
 * backdrop (sticky-note, gradient horizon, etc.) rather than a foreground
 * glyph. Note: the Write app's id is `docs`. Consumed by the dockbar render
 * paths in home.tsx and sidebar.tsx. */
export const FULL_BLEED_BRAND_ICONS = new Set<string>(['draw', 'docs', 'sign']);

/** Per-brand-icon size multiplier on top of the base icon size. Brand icons
 * default to 1.2× because the supplied artwork has more internal padding
 * than lucide line icons. A few apps need extra presence:
 *   - calendar: 1.44× (dark body + small white type needs to read at small sizes)
 *   - system:   1.56× (colourful glyph has lots of internal whitespace)
 *   - tasks:    1.56× (checklist artwork has wide internal margins) */
export function getBrandIconScale(appId: string): number {
  if (appId === 'calendar') return 1.44;
  if (appId === 'system') return 1.56;
  if (appId === 'tasks') return 1.56;
  return 1.2;
}

